import * as React from "react"
import { Link } from "gatsby"

const Layout = ({ location, title, children }) => {
  const rootPath = `${__PATH_PREFIX__}/`
  const isRootPath = location.pathname === rootPath

  const navigation = [
    { path: "/", label: "Écrits" },
    { path: "/a-propos/", label: "À propos" },
    { path: "/brol/", label: "Brol" },
  ].map((item, idx) => (
    <Link key={idx} to={item.path} activeStyle={{ fontWeight: "bold" }}>
      {item.label}
    </Link>
  ))

  return (
    <div className="global-wrapper" data-is-root-path={isRootPath}>
      <header className="global-header">
        <h1 className="main-heading">
          <Link to="/">{title}</Link>
        </h1>

        <div className="main-navigation">{navigation}</div>
      </header>
      <main>{children}</main>
      <footer>
        <small>
          <p style={{ marginBottom: "var(--spacing-3)" }}>
            Ce contenu est disponible sous licence{" "}
            <a
              rel="license"
              href="http://creativecommons.org/licenses/by-sa/4.0/"
            >
              CC BY-SA 4.0
            </a>
            .
          </p>
          <p>
            Vous pouvez souscrire au <Link to="/rss.xml">flux RSS</Link>.
          </p>
        </small>
      </footer>
    </div>
  )
}

export default Layout
